def write_project_file(relative_path: str, content: str) -> None:
    """Write a project file using UTF-8 without BOM."""

    target_path = ROOT_DIR / relative_path
    target_path.parent.mkdir(parents=True, exist_ok=True)
    target_path.write_text(content, encoding="utf-8")


def main() -> None:
    """Create model files and Alembic environment configuration."""

    for relative_path, content in FILES.items():
        write_project_file(relative_path, content)

    print("ADIM 4C model dosyalari olusturuldu.")
    print("")
    print("Simdi su komutlari calistir:")
    print("  cd C:\\missio\\backend")
    print("  .\\.venv\\Scripts\\activate")
    print('  python -m alembic revision --autogenerate -m "baseline schema"')
    print("  python -m alembic upgrade head")
    print("  python -m alembic current")
    print(
        "  python -c \"from sqlalchemy import inspect; "
        "from app.db.session import engine; "
        "tables = inspect(engine).get_table_names(); "
        "print(len(tables)); print('\\n'.join(tables))\""
    )


if __name__ == "__main__":
    main()
